3	export function nextGeneration(cells: Cell[]): Cell[] {
4	  const liveSet = new Set<string>();
5	  for (const [x, y] of cells) {
6	    liveSet.add(`${x},${y}`);
7	  }
8	
9	  const neighborCounts = new Map<string, number>();
10	  for (const [x, y] of cells) {
11	    for (let dx = -1; dx <= 1; dx++) {
12	      for (let dy = -1; dy <= 1; dy++) {
13	        if (dx === 0 && dy === 0) continue;
14	        const nx = x + dx;
15	        const ny = y + dy;
16	        const key = `${nx},${ny}`;
17	        neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
18	      }
19	    }
20	  }
21	
22	  const result: Cell[] = [];
23	  for (const [key, count] of neighborCounts) {
24	    const isAlive = liveSet.has(key);
25	    if (count === 3 || (count === 2 && isAlive)) {
26	      const [xStr, yStr] = key.split(',');
27	      result.push([Number(xStr), Number(yStr)]);
28	    }
29	  }
30	
31	  return result;
